module.exports = function(options) {
  var arg, error, file, i, id, len, ref, ref1;
  if (options == null) {
    options = {};
  }
  if (options.id != null) {
    return options.id;
  }
  id = (ref = process.env.NUCID) != null ? ref : process.env.npm_package_config_nucid;
  ref1 = process.argv;
  for (i = 0, len = ref1.length; i < len; i++) {
    arg = ref1[i];
    if (arg.slice(0, 8) === '--nucid=') {
      id = arg.slice(8);
      break;
    }
  }
  if (!((id != null) || options.noFindId === true)) {
    file = require('path').resolve(process.cwd(), '.nuc.name');
    try {
      id = require('fs').readFileSync(file, 'utf8').trim();
    } catch (error1) {
      error = error1;
      return {
        __error: '`id` required for nuc',
        reason: error
      };
    }
  }
  return options.id = id;
};
